window.DQ_INDEX=[{"u":"articles/adenoid-face.html","t":"口呼吸・お口ぽかん、顔つきや歯並びに影響するの？論文で解説","d":"お口ぽかん（口呼吸）は顔つきや歯並びに影響するの？アデノイド肥大との関係を論文をもとに、悪循環が起きる仕組みと家庭でできる対策を現役歯科医師が解説します。","c":"子どもの歯"},{"u":"articles/baby-chewing.html","t":"赤ちゃんの&quot;噛む力&quot;っていつ育つの？咀嚼の発達を論文で","d":"離乳食、いつから固いものを食べさせていい？赤ちゃんの咀嚼機能がどう発達していくのかを研究をもとに解説。月齢に合わせた進め方のコツを現役歯科医師がまとめます。","c":"食育"},{"u":"articles/baby-led-weaning.html","t":"手づかみ食べ（BLW）ってどうするの？栄養は足りる？","d":"赤ちゃんの手づかみ食べ（BLW）。栄養は足りる？窒息は大丈夫？始め方は？修正版BLWの研究をもとに、進め方の注意点と歯科医がすすめる理由を現役歯科医師が解説します。","c":"食育"},{"u":"articles/bone-augmentation-gbr.html","t":"骨が足りないと言われた…骨造成（GBR）は必要？効くの？論文で","d":"インプラントの前に「骨が足りない」と言われたら。骨造成（GBR・骨移植）でどれくらい土台を作れるのか、埋入したインプラントは何%もつのか、システマティックレビューをもとに現役歯科医師が中立に解説します。","c":"自費・専門治療"},{"u":"articles/breastfeeding-teeth.html","t":"母乳育児って歯並びにいいの？論文で見る母乳と不正咬合","d":"母乳育児は歯並びにいいの？48研究をまとめたメタ解析をもとに、母乳と不正咬合（歯並び・かみ合わせの乱れ）の関係、卒乳後に気をつけたいことを現役歯科医師が解説します。","c":"子どもの歯"},{"u":"articles/bristle-stiffness.html","t":"歯ブラシの硬さは\"やわらかめ\"と\"ふつう\"どっち？論文で検証","d":"硬い毛ほど歯垢は落ちるが歯ぐきは傷つく——研究が示すトレードオフを正直に解説。ランダム化比較試験とシステマティックレビューをもとに、現役歯科医師がフェアにまとめます。","c":"オーラルケア"},{"u":"articles/brush-head-size.html","t":"歯ブラシのヘッドは小さい方がいいの？論文で検証","d":"コンパクトヘッドは本当に有利？ロボット実験では磨き方によって結果が逆転し、ヒトでの比較試験はほとんどありません。エビデンスの限界まで含めて現役歯科医師がフェアに解説します。","c":"オーラルケア"},{"u":"articles/brush-replacement.html","t":"歯ブラシっていつ替えるの？「1ヶ月で交換」の根拠を論文で","d":"歯ブラシは何ヶ月で交換すべき？古いブラシは本当に落ちが悪いのか。3ヶ月使用ブラシと新品を比べた研究や、毛先の開き・細菌汚染の論文をもとに、現役歯科医師がフェアに解説します。","c":"オーラルケア"},{"u":"articles/brushing-method.html","t":"歯の磨き方って結局どれが正解？バス法・スクラビング法を論文で","d":"バス法、スクラビング法、フォーンズ法…どの磨き方が一番いいの？システマティックレビューとネットワークメタ解析をもとに、現役歯科医師がフェアに解説。結論は「決定的な差は示されていない」です。","c":"オーラルケア"},{"u":"articles/brushing-time.html","t":"歯磨きは何分・1日何回すればいいの？2分・2回の根拠を論文で","d":"「2分間・1日2回」はどこまで正しい？1分と2分を比べたメタ解析、ブラッシング回数とむし歯の関係を調べた33件のメタ解析をもとに、現役歯科医師が数字ごとフェアに解説します。","c":"オーラルケア"},{"u":"articles/bruxism-splint.html","t":"歯ぎしりのマウスピース（スプリント）ってどうするの？効果を論文で","d":"歯ぎしり対策のマウスピース（スプリント）は本当に効くのか。コクランレビューをもとに、歯ぎしり自体への効果と、歯の摩耗を守る役割の違いを現役歯科医師が正直に解説します。","c":"歯ぎしり"},{"u":"articles/canker-sore.html","t":"口内炎（アフタ）って何で治すの？治療法を論文で","d":"繰り返す口内炎（再発性アフタ性口内炎）はどうやって治すの？システマティックレビューをもとに、被覆材や塗り薬・レーザーなど痛みを和らげる治療法と、セルフケアのコツを現役歯科医師が解説します。","c":"オーラルケア"},{"u":"articles/ceramic-crown.html","t":"セラミックの被せ物ってどのくらいもつの？","d":"白くてきれいなセラミックの被せ物、でも「割れやすい」って本当？オールセラミックの5年生存率を従来の金属セラミックと比べ、長持ちさせるコツを論文をもとに現役歯科医師が解説します。","c":"オーラルケア"},{"u":"articles/ceramic-lifespan.html","t":"セラミックの被せ物、何年もつ？論文で見る生存率","d":"セラミックの被せ物・ブリッジ・ラミネートベニアは何年もつのか。オールセラミックとメタルセラミックの5年生存率、ジルコニアやモノリシックの違いを、システマティックレビューをもとに現役歯科医師が中立に解説します。","c":"自費・専門治療"},{"u":"articles/ceramic-vs-metal-update.html","t":"オールセラミック vs メタルセラミック、その後の10年で何が更新されたか｜昔の常識 vs 最新エビデンス","d":"2015年Sailerのシステマティックレビューは単冠の5年生存率を示しました。では2020年のエンドクラウンのメタアナリシスはその「更新版」なのか。結論、同じ問いではありません。比較が成立しない理由を歯科医師向けに正確に整理します。","c":"補綴"},{"u":"articles/charcoal-toothpaste.html","t":"炭（チャコール）の歯磨き粉って安全？効果ある？論文で","d":"SNSで話題の炭（チャコール）歯みがき粉。本当に白くなる？安全なの？システマティックレビューをもとに、効果のエビデンスと研磨リスクを現役歯科医師が正直に解説します。","c":"オーラルケア"},{"u":"articles/chewing.html","t":"「30回噛みなさい」って本当に効果あるの？よく噛む効果を論文で","d":"よく噛むと食べ過ぎを防げるのか。学術研究をもとに、咀嚼回数とエネルギー摂取・空腹ホルモンの関係を現役歯科医師が解説します。","c":"食と歯"},{"u":"articles/chlorhexidine-update.html","t":"クロルヘキシジン洗口液、いま何がわかっているのか｜昔の常識 vs 最新エビデンス","d":"CHX洗口液は「歯肉炎に効く」で止まっていないか。2017年コクランレビューと2020年ナラティブレビューを読み比べ、プラーク・歯肉炎・歯周炎・着色・アナフィラキシー、そして日本の濃度事情まで歯科医師向けに整理します。","c":"オーラルケア"},{"u":"articles/chx-mouthwash.html","t":"クロルヘキシジンのうがい薬って効くの？使い続けて大丈夫？","d":"クロルヘキシジン(CHX)洗口液は歯垢や歯肉炎に効くの？長く使って平気？コクランレビューをもとに、プラーク抑制効果と着色などの副作用、上手な使い方を現役歯科医師が解説します。","c":"オーラルケア"},{"u":"articles/clear-aligner-adult.html","t":"大人のマウスピース矯正、郵送型ってどうなの？論文で見る効果と注意点","d":"大人のマウスピース矯正（クリアアライナー）。軽度〜中等度には選択肢ですが、歯を大きく動かす複雑な症例では限界があると報告されています。とくに郵送型（対面診査なし）の注意点を、現役歯科医師が中立に解説します。","c":"矯正"},{"u":"articles/composite-vs-amalgam.html","t":"白い詰め物と銀歯、どっちがいいの？寿命を論文で比較","d":"白い詰め物（コンポジットレジン）と銀歯（アマルガム）、結局どっちが長持ち？コクランレビューをもとに、失敗リスク・二次むし歯・見た目・安全性の違いを現役歯科医師が中立に解説します。","c":"オーラルケア"},{"u":"articles/cracked-tooth.html","t":"歯にヒビ（亀裂）が入るとどうなるの？原因と対処を論文で","d":"噛むとズキッと痛むのに、レントゲンでは異常なし。歯のヒビ（クラックトゥース／歯の破折）が心配な方へ。レビュー論文をもとに、原因・見つけ方・進行を防ぐ対処を現役歯科医師が解説します。","c":"オーラルケア"},{"u":"articles/dental-erosion.html","t":"酸蝕歯（歯が酸で溶ける）ってどうするの？予防を論文で","d":"酸っぱい飲食物で歯が溶ける「酸蝕歯」。すぐ歯みがきしていい？システマティックレビューをもとに、酸蝕歯の予防・進行を抑えるコツを現役歯科医師が解説します。","c":"オーラルケア"},{"u":"articles/dental-visit-value.html","t":"歯医者に通うのは得なのか損なのか｜75歳以上43万人のデータで見る","d":"痛くないのに歯科へ通うのは割に合うのか。日本の75歳以上43万人を条件をそろえて比べたレセプト研究、10年以上フォローした歯周治療399人の費用の記録、そして米国とドイツで結論が割れている医療費の研究を、現役歯科医師が原典にあたって解説します。","c":"全身と歯"},{"u":"articles/denture-adhesive.html","t":"入れ歯安定剤ってどう使うの？選び方は？論文で解説","d":"入れ歯安定剤は使ってもいいの？選び方や使い方のコツは？維持力や満足度を調べた研究をもとに、上手な使い方と注意点を現役歯科医師が解説します。","c":"入れ歯"},{"u":"articles/denture-cleaning.html","t":"入れ歯の洗浄って結局どうするの？ブラシと洗浄剤どっち？","d":"入れ歯はブラシでこするだけでいい？洗浄剤に浸けるべき？コクランレビューをもとに、機械的清掃と化学洗浄の使い分け、毎日のお手入れの基本を現役歯科医師が解説します。","c":"入れ歯"},{"u":"articles/denture-night.html","t":"入れ歯は夜つけたまま寝ていいの？肺炎リスクを論文で","d":"入れ歯は夜も入れたまま寝て大丈夫？高齢者を対象にした研究をもとに、夜間の義歯装着と肺炎リスクの関係、外して保管するときのお手入れを現役歯科医師が解説します。","c":"入れ歯"},{"u":"articles/denture-stomatitis.html","t":"入れ歯の下が赤い・痛い…義歯性口内炎ってどうするの？","d":"入れ歯を外すと歯ぐきが赤い、ヒリヒリ痛む。それは義歯性口内炎かもしれません。夜間の装着やカンジダ菌との関係、清掃と対処のコツを現役歯科医師が論文をもとに解説します。","c":"入れ歯"},{"u":"articles/diabetes-implant.html","t":"糖尿病でもインプラントできるの？","d":"糖尿病だとインプラントは無理？と諦めていませんか。血糖コントロールとインプラント成功率の関係を論文をもとに、治療前に整えておきたいポイントを現役歯科医師が解説します。","c":"インプラント"},{"u":"articles/dry-mouth.html","t":"ドライマウス（口腔乾燥）ってどうするの？対処法を論文で","d":"口の中がネバつく・乾く「ドライマウス」。原因や、保湿ジェル・洗口液・唾液を出す工夫はどこまで効くの？アンブレラレビューをもとに、現役歯科医師が対処法をやさしく解説します。","c":"オーラルケア"},{"u":"articles/early-childhood-caries.html","t":"乳歯の虫歯、何が原因でどう防ぐの？論文で解説","d":"乳歯の虫歯（乳幼児う蝕）は何が原因？ミュータンス菌や既にある虫歯がリスクになるって本当？子どもの虫歯の予防のコツを、論文をもとに現役歯科医師が解説します。","c":"子どもの歯"},{"u":"articles/early-ortho-class2.html","t":"出っ歯の子、早めに矯正した方がいいの？論文で解説","d":"子どもの出っ歯（上顎前突）は早めに矯正すべき？早期の2段階治療のメリットや、前歯のケガのリスクとの関係を、コクランレビューをもとに現役歯科医師が解説します。","c":"子どもの歯"},{"u":"articles/electric-toothbrush.html","t":"電動歯ブラシと手用、どっちがいいの？論文でわかる結論【音波式vs回転式も】","d":"電動歯ブラシは手用より本当に良い？コクランレビューなど信頼性の高い論文をもとに、歯垢・歯肉炎の減り方、音波式と回転式の違い、選び方まで歯科の視点で正直に解説します。","c":"オーラルケア"},{"u":"articles/floss-interdental.html","t":"フロスと歯間ブラシ、どっちがいいの？論文でわかる使い分け","d":"フロスと歯間ブラシ、買うべきはどっち？コクランレビューをもとに、歯肉炎への効果とすき間による正しい使い分け、サイズ選びのコツを解説します。","c":"オーラルケア"},{"u":"articles/floss-types.html","t":"フロスはどれを選べばいいの？ワックス付き・糸ようじ・テープを論文で比較","d":"ワックス付きとワックスなし、糸ようじ（ホルダー型）と手巻き、デンタルテープ。フロスの種類で汚れ落ちは変わるのか、実際の比較研究をもとに現役歯科医師が正直に解説します。","c":"オーラルケア"},{"u":"articles/fluoride-ppm.html","t":"歯磨き粉のフッ素、何ppm選べばいいの？濃度と効果を論文で","d":"フッ素は濃い方が効くの？コクランレビューをもとに、フッ素濃度とむし歯予防効果の関係、大人・子どもで選ぶべきppm、使い方のコツを現役歯科医師が解説します。","c":"オーラルケア"},{"u":"articles/fluoride-rinse.html","t":"フッ素のうがい（フッ化物洗口）って子どもに必要？効果を論文で","d":"学校や家庭でのフッ化物洗口、本当に子どものむし歯予防になるの？コクランレビューをもとに、効果の大きさ・始める年齢・使い方の注意点を現役歯科医師が解説します。","c":"子どもの歯"},{"u":"articles/fluoride-safety.html","t":"フッ素は体に悪いの？安全性を論文で冷静に整理","d":"「フッ素は危険」「体に悪い」は本当？結論はフッ素は","c":"オーラルケア"},{"u":"articles/fluoride-varnish-nma-update.html","t":"歯医者で塗るフッ素、本当に効くのはどれ？最新ネットワークメタ解析","d":"子どものむし歯予防で歯科医院が塗る「フッ素」。8種類の塗り方を比べた最新のネットワークメタ解析では、対照より明確に効いたのは一部だけでした。現役歯科医師がエビデンスの中身を中立に解説します。","c":"昔の常識 vs 最新"},{"u":"articles/fluoride-varnish.html","t":"歯医者さんのフッ素塗布ってどのくらい虫歯を防ぐの？論文で","d":"歯科医院で塗るフッ素（フッ化物バーニッシュ）は、市販の歯磨き粉と何が違い、どのくらい虫歯を防ぐのか。コクランレビューをもとに、効果の目安と受ける頻度を現役歯科医師が解説します。","c":"子どもの歯"},{"u":"articles/fluorosis.html","t":"フッ素の摂りすぎで歯に白い斑点？歯のフッ素症を論文で","d":"子どもの歯に白い斑点。フッ素の摂りすぎ（歯のフッ素症）が心配な方へ。コクランレビューをもとに、適量なら安全な理由、年齢に合った濃度と量、飲み込ませないコツを現役歯科医師が解説します。","c":"子どもの歯"},{"u":"articles/full-mouth-vs-quadrant.html","t":"歯周病治療は一気にやった方がいいの？フルマウス法を論文で","d":"歯周病の歯石取りは一気にやる方が効果的なの？フルマウス一括法と分割法（1回1ブロック）の違いをコクランレビューをもとに、現役歯科医師が解説します。","c":"歯周病"},{"u":"articles/gingivitis-plaque.html","t":"歯みがきをサボると歯ぐきはどうなるの？歯肉炎を論文で","d":"歯みがきをやめると歯ぐきはどう変わる？プラークと歯肉炎の関係を調べた古典的な研究をもとに、歯肉炎が起こるまでの日数と回復のしくみを現役歯科医師が解説します。","c":"オーラルケア"},{"u":"articles/gum-recession.html","t":"歯茎が下がる（歯肉退縮）のはなぜ？戻せるの？論文で","d":"歯茎が下がって歯が長く見える「歯肉退縮」。自然には戻らないの？システマティックレビューをもとに、原因・進行を止める方法・外科で覆える場合を現役歯科医師が解説します。","c":"全身と歯"},{"u":"articles/implant-20year.html","t":"インプラントの20年生存率は93.0%｜前向き研究のみのSR/MAを読む","d":"20年以上追跡した前向き研究のみを対象としたシステマティックレビュー/メタ解析（2026）で、インプラント20年生存率は93.0%（95%CI 91.6-94.1）、プール平均MBLは1.11mm。確実性moderate・異質性大という限界と、この研究では言えないことまで歯科医師向けに整理します。","c":"インプラント"},{"u":"articles/implant-bridge-denture.html","t":"歯を失ったら？インプラント・ブリッジ・入れ歯を論文で比べる","d":"歯を失ったとき、インプラント・ブリッジ・入れ歯のどれを選ぶ？10年後にどれだけ残るのか、トラブルはどれが多いのか、システマティックレビューをもとに現役歯科医師が中立に比較します。","c":"自費・専門治療"},{"u":"articles/implant-lifespan.html","t":"インプラントって何年もつの？10年生存率を論文で","d":"インプラントは何年もつ？長期の追跡研究をもとに、10年以上の累積生存率、長持ちさせるために欠かせないメンテナンスのポイントを現役歯科医師が正直に解説します。","c":"インプラント"},{"u":"articles/implant-maintenance.html","t":"インプラントのメインテナンスってどのくらいの頻度？","d":"せっかく入れたインプラント、放っておくと抜けることも。定期メンテナンスがインプラント周囲炎をどれだけ防ぐのか、通う頻度の目安を論文をもとに現役歯科医師が解説します。","c":"インプラント"},{"u":"articles/implant-overdenture.html","t":"下の総入れ歯が動く…インプラントで固定する治療は？","d":"下の総入れ歯がしゃべると浮く、噛むとズレる。インプラントで固定するオーバーデンチャーとは？従来の入れ歯との満足度・QOLの違いを、現役歯科医師が論文をもとに解説します。","c":"入れ歯"},{"u":"articles/interdental-cleaning-update.html","t":"歯間清掃は結局どれがいいのか｜昔の常識 vs 最新エビデンス","d":"フロスvs歯間ブラシvsウォーターフロス。デバイスごとにバラバラに評価されてきた歯間清掃を、2020年のネットワークメタ解析が横断比較しようとした。しかし結論は「強い結論は出せない」。歯周メンテナンス患者を対象とした最新像を歯科医師向けに整理します。","c":"オーラルケア"},{"u":"articles/intraoral-scanner.html","t":"歯型取りが光スキャンに？口腔内スキャナーの精度は？","d":"あの苦しい歯型取りがカメラで撮るだけに。口腔内スキャナー（IOS）は従来の型取りとどこまで精度が並ぶのか、苦手な場面はどこか、論文をもとに現役歯科医師が解説します。","c":"インプラント"},{"u":"articles/keep-teeth-30y.html","t":"一生自分の歯で噛むにはどうするの？30年の研究で","d":"自分の歯を一生残すことはできる？30年間、定期メンテナンスを続けた人を追った研究をもとに、失う歯をどこまで減らせるのか、そのために必要なことを現役歯科医師が解説します。","c":"オーラルケア"},{"u":"articles/kids-chewing-obesity.html","t":"早食いの子は太りやすい？学童の追跡研究で見る食べる速さと体重","d":"早食いの子は太りやすいの？小学4年生を3年間追いかけた日本のコホート研究などをもとに、食べる速さと過体重の関係、家庭でできる『ゆっくり噛んで食べる』工夫を現役歯科医師が解説します。","c":"食育"},{"u":"articles/kids-malocclusion.html","t":"子どもの歯並び、乳歯のうちからどうするの？現役歯科医師が解説","d":"乳歯のうちから歯並びは気にすべき？子どもの不正咬合の世界的な有病率や、家庭でできること・受診の目安を、論文をもとに現役歯科医師がやさしく解説します。","c":"子どもの歯"},{"u":"articles/mft.html","t":"MFT（口の体操）ってどうするの？歯並びに効くの？論文で解説","d":"MFT（口腔筋機能療法・口の体操）って歯並びに効くの？矯正の補助としての有効性を論文をもとに、何をする訓練なのか、向いているケースを現役歯科医師が解説します。","c":"子どもの歯"},{"u":"articles/mi-paste-remin.html","t":"初期虫歯（白い斑点）は削らず治せるの？再石灰化を論文で","d":"歯の白い斑点（初期虫歯）は削らずに戻せるの？CPP-ACP（MIペースト）の再石灰化効果を検証した論文をもとに、白斑への働きと家庭でのケアのコツを現役歯科医師が解説します。","c":"オーラルケア"},{"u":"articles/mouth-breathing.html","t":"お口ぽかん（口呼吸）って顔の発育に影響するの？論文で解説","d":"子どもの口呼吸は顔やあごの発育に影響するのか。BMC Oral Healthの研究をもとに、口呼吸とあご・気道の関係、早めに相談すべきサインを現役歯科医師が解説します。","c":"子どもの歯"},{"u":"articles/mouthwash-ingredients.html","t":"洗口液は成分で選ぶ？CPC・エッセンシャルオイル・CHXを論文で比較","d":"マウスウォッシュのCPC・エッセンシャルオイル・クロルヘキシジン。成分によって効果は違うのか、ネットワークメタ解析をもとに順位と限界を現役歯科医師が正直に解説します。","c":"オーラルケア"},{"u":"articles/mouthwash.html","t":"マウスウォッシュは歯みがきの代わりになるの？論文で解説","d":"洗口液（マウスウォッシュ）だけで歯みがきの代わりになる？コクランレビューなどをもとに、洗口液の本当の効果と正しい使い方、CHXとリステリンの違いを現役歯科医師が解説します。","c":"オーラルケア"},{"u":"articles/oil-pulling.html","t":"オイルプリング（油うがい）って効くの？エビデンスを論文で","d":"ココナッツオイルなどでうがいするオイルプリングは歯やお口に効くの？システマティックレビューをもとに、プラークや歯ぐきへの効果と、エビデンスの限界を現役歯科医師が正直に解説します。","c":"オーラルケア"},{"u":"articles/oral-cancer-signs.html","t":"口内炎が治らない…口腔がんのサイン？受診の目安を論文で","d":"なかなか治らない口内炎や、口の中の白い斑（白板症）。口腔がんとの関係や、受診すべき目安を、システマティックレビューをもとに現役歯科医師が中立に解説します。不安をあおらず、正しい行動の目安を。","c":"口腔がん・粘膜"},{"u":"articles/oral-care-pneumonia.html","t":"口腔ケアで肺炎って本当に防げるの？介護現場の研究で解説","d":"口腔ケアで誤嚥性肺炎は防げる？施設高齢者を対象にした研究をもとに、専門的な口腔ケアと肺炎予防の関係を現役歯科医師が解説します。","c":"高齢と歯"},{"u":"articles/oral-frailty-update.html","t":"オーラルフレイルは、いま何がわかっているのか","d":"オーラルフレイルは日本の柏スタディ（Tanaka 2018）で6項目の操作的定義として提示され、2021年のLancet Healthy Longevityのシステマティックレビューでは39研究に12指標が混在していた。旧新2本の論文から、定義・数値・言えないことを歯科医師向けに整理します。","c":"高齢と歯"},{"u":"articles/oral-frailty.html","t":"オーラルフレイルってどうするの？放置するとどうなる？","d":"オーラルフレイル(口の衰え)ってなに？放置するとどうなる？高齢者を追った研究をもとに、身体の衰えや死亡リスクとの関連、早めに気づいて対処するコツを現役歯科医師が解説します。","c":"高齢と歯"},{"u":"articles/oral-hypofunction.html","t":"口腔機能低下症って何？チェック方法は？","d":"むせる、食べこぼす、滑舌が落ちた。加齢による口の衰えは「口腔機能低下症」として7項目で診断されます。どんな検査で何がわかるのか、家庭での気づきのサインを現役歯科医師が論文をもとに解説します。","c":"高齢と歯"},{"u":"articles/osa-oral-appliance.html","t":"いびき・睡眠時無呼吸の歯科マウスピース（OA）ってどうするの？効果を論文で","d":"歯科で作るマウスピース（口腔内装置・OA）はいびきや睡眠時無呼吸に効くの？コクランレビューをもとに、OAの効果とCPAPとの違い、向いている人を現役歯科医師が解説します。","c":"歯ぎしり"},{"u":"articles/pacifier-malocclusion-update.html","t":"おしゃぶりと不正咬合、エビデンスはどこまで言えるのか｜昔の常識 vs 最新エビデンス","d":"「おしゃぶりは開咬・交叉咬合の原因」は、実はメタアナリシスで裏づけられていません。2018年のシステマティックレビューと2022年の有病率レビューを読み比べ、RRが存在しないこと、開咬の定義そのものが揺れていることを歯科医師向けに整理します。","c":"子どもの歯"},{"u":"articles/pacifier-sids.html","t":"おしゃぶりって使っていいの？SIDS対策になる？論文で解説","d":"おしゃぶりは歯並びに悪い？でもSIDS（乳幼児突然死症候群）対策になるって本当？就寝時のおしゃぶりと乳幼児突然死のリスクの関係を、論文をもとに現役歯科医師が解説します。","c":"子どもの歯"},{"u":"articles/pacifier-thumb.html","t":"指しゃぶり・おしゃぶり、歯並びに影響するの？やめる目安は？","d":"指しゃぶりやおしゃぶりは歯並びに悪い？いつまでにやめる？SIDS予防の利点との功罪も含め、現役歯科医師が論文をもとに卒業の目安とやめさせ方を解説します。","c":"子どもの歯"},{"u":"articles/peri-implantitis-prevalence.html","t":"インプラント周囲炎は結局どれくらい起きるのか｜2014年の常識と最新メタ解析","d":"「インプラント周囲炎は約22%」——2014年のDerksらの数字は今も生きているのか。2022年のメタ解析（患者レベル19.53%／インプラントレベル12.53%）と並べ、なぜ数字が違うのかを症例定義の観点から歯科医師向けに整理します。","c":"インプラント"},{"u":"articles/peri-implantitis.html","t":"インプラント周囲炎ってどのくらい起こるの？頻度とケアを論文で","d":"インプラントを入れたあとに起こる「周囲炎」。どのくらいの人に起こるのか、天然歯の歯周病と何が違うのか、日々のケアで防げるのかを、現役歯科医師が論文をもとに解説します。","c":"インプラント"},{"u":"articles/perio-diabetes.html","t":"歯周病を治すと糖尿病もよくなるの？論文で検証","d":"歯周病の治療で糖尿病の数値は変わる？歯周治療とHbA1cの関係を調べたコクランレビューをもとに、口の健康と血糖のつながりを現役歯科医師が正直に解説します。","c":"全身と歯"},{"u":"articles/perio-heart.html","t":"歯周病って心臓の病気と関係あるの？口と全身のつながりを論文で","d":"歯周病は心臓・血管の病気とどう関わるの？ヨーロッパ歯周病連盟のコンセンサスをもとに、歯周炎が心血管疾患の修飾できるリスク因子とされる理由と、今日からできる対策を現役歯科医師が解説します。","c":"全身と歯"},{"u":"articles/perio-staging.html","t":"自分の歯周病はどのくらい進んでるの？ステージとグレードで見る進行度","d":"歯周病の進行度は「ステージ」と「グレード」で評価します。2018年の新しい国際分類をもとに、自分の歯周病がどのくらい進んでいるのか、何を見て判断するのかを現役歯科医師が解説します。","c":"歯周病"},{"u":"articles/perioperative-oral.html","t":"手術前の歯科受診（周術期口腔機能管理）ってどうするの？","d":"大きな手術の前になぜ歯医者？周術期口腔機能管理の目的を、日本の大規模データをもとに解説。術後肺炎との関係、受診の流れ、家庭でのケアを現役歯科医師がまとめます。","c":"高齢と歯"},{"u":"articles/post-brushing-rinse.html","t":"歯みがきのあと、口をゆすぐとフッ素は流れる？「すすぎは1回」を論文で","d":"「歯みがきのあとはゆすぎすぎない方がいい」は本当か。口に残るフッ素の量、歯と歯の間に残る量、そして3年間むし歯そのものを追った試験の結果まで、わかっていることと「わかっていないこと」を現役歯科医師が正直に整理します。","c":"オーラルケア"},{"u":"articles/power-brush-type-update.html","t":"電動歯ブラシ、回転式と音波式どっちがいい？最新の比較","d":"電動歯ブラシの「回転式（オシレーティング・ロテーティング）」と「音波式（高頻度）」。プラーク除去を比べたレビューでは回転式がわずかに優位でしたが、4週間の使用を比べた独立系レビューは「差なし」と結論しています。決着していない理由と現実的な選び方を、現役歯科医師が中立に解説します。","c":"昔の常識 vs 最新"},{"u":"articles/precision-endo.html","t":"精密根管治療（マイクロ・ラバーダム）で何が変わる？論文で見る成功率","d":"マイクロスコープやラバーダムを使う「精密根管治療」。根管治療の成功率や、精度を高める要素を、システマティックレビューをもとに現役歯科医師が中立に解説します。","c":"自費・専門治療"},{"u":"articles/pregnancy-dental.html","t":"妊娠中に歯の治療はできるの？安全性と「カルシウムを取られる」の真偽を論文で","d":"妊娠中の歯科治療は本当に危ないのか。安定期に治療を受けた823人の研究、歯周治療と早産の関係を調べたコクランレビュー、そして「赤ちゃんが母親の歯からカルシウムを吸収する」という説の出どころを、現役歯科医師が原典にあたって解説します。","c":"子どもの歯"},{"u":"articles/probiotics-oral.html","t":"乳酸菌（プロバイオティクス）は虫歯・歯周病に効くの？論文で","d":"口腔用の乳酸菌・プロバイオティクスは虫歯や歯周病に効くの？システマティックレビュー＆メタ分析をもとに、むし歯菌や歯ぐきへの効果と限界を現役歯科医師が正直に解説します。","c":"オーラルケア"},{"u":"articles/pulp-capping-mta.html","t":"神経を残す治療（直接覆髄）ってどうするの？MTAって？","d":"虫歯が神経に近いとき、神経を残す「直接覆髄」という選択肢があります。使われる材料MTAと水酸化カルシウムの違いを、論文をもとに現役歯科医師が解説します。","c":"歯内療法"},{"u":"articles/recall-interval.html","t":"歯の定期検診って何ヶ月ごとに行けばいいの？間隔を論文で","d":"定期検診は半年ごと？3ヶ月ごと？「間隔を延ばしても大丈夫」の根拠とされる英国INTERVAL試験で、延長してよいと判断されたのは参加者の27%だけでした。そして3ヶ月間隔はそもそも比較されていません。原典にあたって現役歯科医師が解説します。","c":"オーラルケア"},{"u":"articles/regular-cleaning.html","t":"定期的な歯のクリーニングって意味あるの？論文で検証","d":"歯のクリーニングは定期的に通う価値がある？プロのケアと清掃指導を6年続けた人を追った研究をもとに、むし歯や歯ぐきの後退がどう変わるかを現役歯科医師が解説します。","c":"オーラルケア"},{"u":"articles/resin-infiltration.html","t":"隣の歯との間の初期虫歯、削らず止められるの？レジン浸潤を論文で","d":"歯と歯の間にできた初期の虫歯、いきなり削るしかないの？削らずに進行を抑える「レジン浸潤(Icon)」という選択肢があります。研究をもとに、その効果と向き不向きを現役歯科医師が解説します。","c":"オーラルケア"},{"u":"articles/ridge-preservation.html","t":"抜歯した後の骨、放っておくと痩せる？ソケットプリザベーション","d":"歯を抜いた後、あごの骨は自然に痩せていきます。「ソケットプリザベーション（抜歯窩の骨温存）」で骨の吸収をどれだけ抑えられるのか、システマティックレビューをもとに現役歯科医師が中立に解説します。","c":"自費・専門治療"},{"u":"articles/rme-enuresis.html","t":"おねしょが治らない…上顎拡大で改善するの？論文で解説","d":"治りにくいおねしょ（夜尿症）に、歯科の上顎急速拡大（RME）が関係するって本当？上あごの拡大と夜尿の関係を、論文をもとに現役歯科医師がやさしく解説します。","c":"子どもの歯"},{"u":"articles/root-canal-success-update.html","t":"根管治療の成功率は、結局いくつなのか｜昔の常識 vs 最新エビデンス","d":"根管治療の成功率「◯%」は、判定基準を決めなければ意味を持たない。Ng 2007のシステマティックレビューと、2022年の更新版（Burns）を読み比べ、strict 82.0%とloose 92.6%が何を測った数字なのかを歯科医師向けに整理します。","c":"歯内療法"},{"u":"articles/root-canal-success.html","t":"根管治療の成功率ってどのくらいなの？論文で見る歯内療法","d":"根管治療（歯の神経の治療）の成功率はどのくらい？系統的レビューをもとに、初回治療の成功率、成功を左右する条件、再治療の考え方を現役歯科医師が解説します。","c":"歯内療法"},{"u":"articles/rubber-dam.html","t":"根管治療のラバーダムって本当に必要なの？論文で解説","d":"根管治療で口にかけるゴムのシート「ラバーダム」。本当に必要？歯の生存率を調べた研究をもとに、その役割と効果を現役歯科医師がやさしく解説します。","c":"歯内療法"},{"u":"articles/sdf-silver.html","t":"サホライド（SDF）で虫歯の進行は止められるの？黒くなる？論文で","d":"子どもの虫歯に塗る「サホライド（38%SDF）」は本当に進行を止められるのか、そして黒くなるのはなぜか。系統的レビューをもとに、効果と見た目のトレードオフを現役歯科医師が正直に解説します。","c":"子どもの歯"},{"u":"articles/sealant-primary-update.html","t":"乳歯のシーラントは本当に効く？最新の研究で見直し","d":"子どもの奥歯に詰める「シーラント（予防充填）」。永久歯では有効性が確立していますが、乳歯（乳臼歯）に限ると質の高い研究が不足しているという最新のシステマティックレビューを、現役歯科医師が中立に解説します。","c":"昔の常識 vs 最新"},{"u":"articles/sealant.html","t":"奥歯の溝を埋めるシーラントって虫歯予防になるの？論文で","d":"子どもの奥歯の溝を樹脂で埋める「シーラント」。本当にむし歯予防になるのか、コクランレビューをもとに効果と限界、いつ受けるべきかを現役歯科医師がやさしく解説します。","c":"子どもの歯"},{"u":"articles/senior-powered-brush.html","t":"高齢の親に電動歯ブラシを買うべき？55歳以上では差が出なかった","d":"電動歯ブラシは手用より優れるとされますが、55歳以上に限った解析では歯垢・歯ぐきのどの指標でも差が出ませんでした。買い替えを迷っている方へ、現役歯科医師が正直に整理します。","c":"高齢と歯"},{"u":"articles/sensitivity-toothpaste.html","t":"知覚過敏の歯磨き粉（硝酸カリウム）って効くの？論文で","d":"冷たいものでしみる知覚過敏。シュミテクトなどに入っている硝酸カリウムは本当に効くのか、どのくらいの期間で効いてくるのかを、現役歯科医師がコクランレビューをもとに解説します。","c":"オーラルケア"},{"u":"articles/shortened-dental-arch.html","t":"奥歯がなくても大丈夫？短縮歯列（ショートアーチ）って？","d":"一番奥の歯を失った、入れ歯を作るか迷う。実は奥歯が全部そろっていなくても機能を保てるという「短縮歯列」の考え方があります。どこまで残せばいいのか、現役歯科医師が論文をもとに解説します。","c":"入れ歯"},{"u":"articles/single-multi-visit.html","t":"根管治療って1回で終わらせていいの？論文で解説","d":"根管治療は1回で終わる？それとも複数回に分けるべき？単回法と複数回法を比べたコクランレビューをもとに、治り方の違いを現役歯科医師が解説します。","c":"歯内療法"},{"u":"articles/smoking-implant-update.html","t":"喫煙はインプラントをどれだけ失敗させるのか｜「本数」で見た最新の知見","d":"「喫煙者は失敗しやすい」から「喫煙量で差があるか」へ。2015年のChrcanovicらのメタ解析（107研究）と2020年のNaseriらの本数別メタ解析（23研究）を比較し、歯科医師向けにRR・信頼区間と限界を整理します。","c":"インプラント"},{"u":"articles/smoking-implant.html","t":"タバコを吸っているとインプラントは失敗しやすいの？論文で","d":"喫煙はインプラント治療にどう影響するのか。禁煙しないと入れられないのか、失敗リスクはどれくらい上がるのかを、現役歯科医師が論文をもとにフェアに解説します。","c":"インプラント"},{"u":"articles/spt-maintenance.html","t":"歯周病が治った後のメンテナンスって必要なの？SPTを論文で","d":"歯周病の治療が終わったら通院はもう終わり？いいえ、その後の定期メンテナンス(SPT)こそが歯を守るカギです。コクランレビューをもとに、なぜ続ける必要があるのかを現役歯科医師が解説します。","c":"歯周病"},{"u":"articles/spt-tooth-loss.html","t":"歯周メンテ(SPT)ってサボると歯を失うの？通院遵守と歯の喪失","d":"歯周病のメンテナンス、忙しくてつい間隔が空いてしまう…。実は通院を守れるかどうかで歯の残り方が変わります。研究をもとに、SPTの遵守と歯の喪失の関係を現役歯科医師が解説します。","c":"歯周病"},{"u":"articles/srp-scaling.html","t":"歯石取り（SRP）ってどのくらい効果あるの？論文で","d":"歯ぐきの中の歯石取り（SRP）は本当に効くの？歯周ポケットへの効果を調べた研究をもとに、SRPで何がどこまで改善するのか、通院前に知っておきたいことを現役歯科医師が解説します。","c":"オーラルケア"},{"u":"articles/sugar-caries.html","t":"砂糖をどれくらい減らせば虫歯にならないの？糖と虫歯の量を論文で","d":"砂糖と虫歯の関係を、WHOのガイドラインの根拠にもなった系統的レビューをもとに解説。1日どれくらいまでなら虫歯が増えにくいのか、遊離糖の考え方を現役歯科医師が正直に説明します。","c":"食と歯"},{"u":"articles/sugar-gingivitis-update.html","t":"砂糖はむし歯だけ？じつは歯ぐきの炎症にも関係","d":"砂糖はむし歯の原因として知られますが、最新のシステマティックレビューでは「砂糖を減らすと歯ぐきの炎症も減る」という関連が示されました。歯みがきとは別の切り口の予防を、現役歯科医師が中立に解説します。","c":"昔の常識 vs 最新"},{"u":"articles/tapered-bristles.html","t":"テーパー毛（先細毛）とラウンド毛、どっちがいいの？論文で検証","d":"先細毛はラウンド毛より本当に優秀？システマティックレビューでは「プラーク除去に差なし」と報告されています。歯ぐきへのやさしさは？現役歯科医師が論文をもとにフェアに解説します。","c":"オーラルケア"},{"u":"articles/teeth-eruption.html","t":"赤ちゃんの歯っていつ生える？生えないと心配？","d":"赤ちゃんの歯はいつ生えるの？なかなか生えないと心配？系統的レビューをもとに、乳歯が生える時期・順番、地域差、様子を見ていい目安を現役歯科医師が解説します。","c":"子どもの歯"},{"u":"articles/teeth-longevity.html","t":"歯の数と寿命って関係あるの？残存歯と健康を論文で","d":"歯が多く残っている人は長生き？残存歯数や噛み合わせと死亡リスクの関係を、日本の追跡研究をもとに解説。今日からできる歯を守るケアを現役歯科医師がまとめます。","c":"高齢と歯"},{"u":"articles/tmj-splint.html","t":"あごが痛い・カクカク（顎関節症）にマウスピースは効く？論文で見る","d":"あごの痛みや音（顎関節症）に使うスプリント（マウスピース）。実際に効くのか、システマティックレビューをもとに現役歯科医師が中立に解説します。短期の痛み軽減と、長期の限界まで正直に。","c":"顎関節症"},{"u":"articles/tongue-halitosis.html","t":"舌みがきって口臭に効くの？舌クリーナーの効果を論文で","d":"舌の掃除で口臭は本当に減るのか。コクランレビューをもとに、舌クリーナーが揮発性硫黄化合物（口臭のもと）に与える効果と、その持続性の限界を現役歯科医師が正直に解説します。","c":"口臭"},{"u":"articles/tongue-tie.html","t":"舌小帯って切った方がいいの？授乳がうまくいかない時","d":"赤ちゃんの舌小帯（舌のスジ）、切った方がいいの？コクランレビューをもとに、舌小帯切除と授乳・乳頭痛の関係、判断のポイントを現役歯科医師が解説します。","c":"子どもの歯"},{"u":"articles/tooth-autotransplant.html","t":"自家歯牙移植ってどうなの？自分の歯を移す治療の生存率","d":"親知らずなど自分の歯を、抜けた場所へ移す「自家歯牙移植」。生存率や向いているケースを、システマティックレビューをもとに現役歯科医師が中立に解説します。","c":"自費・専門治療"},{"u":"articles/toothbrush-brand.html","t":"電動歯ブラシ、メーカーで違うの？ブランド比較試験の読み方","d":"オーラルBとソニッケアーを直接比べた試験は存在します。ただしその資金源を見ると、消費者が「このメーカーが上」と受け取れる根拠にはなりません。誰が研究したかの読み方を現役歯科医師が解説します。","c":"オーラルケア"},{"u":"articles/water-flosser.html","t":"ウォーターフロス（口腔洗浄機）って効くの？効果を論文で","d":"水流で歯の間を洗う「ウォーターフロス（口腔洗浄機）」。プラークは落ちるの？歯ぐきには？糸のフロスの代わりになる？システマティックレビューをもとに現役歯科医師が解説します。","c":"オーラルケア"},{"u":"articles/whitening-concentration.html","t":"ホワイトニングは「濃いほど白い」？濃度としみるリスク","d":"ホワイトニングの薬剤は濃いほうがよく白くなる——そう思われがちですが、システマティックレビューの結果は少し違いました。濃度と「しみる（知覚過敏）」・色の変化の関係を、現役歯科医師が中立に解説します。","c":"ホワイトニング"},{"u":"articles/whitening-home-vs-office.html","t":"ホームとオフィス、ホワイトニングはどっちがいい？論文で比較","d":"自宅で行うホームホワイトニングと、歯科医院のオフィスホワイトニング。効果や「しみる」リスクに差はあるのでしょうか。システマティックレビューをもとに、現役歯科医師が中立に比較します。","c":"ホワイトニング"},{"u":"articles/whitening-home.html","t":"市販のホワイトニングって効くの？安全なの？論文で","d":"ドラッグストアや通販で買えるホームホワイトニング。本当に白くなるのか、しみたり歯ぐきが荒れたりしないのかを、現役歯科医師がコクランレビューをもとに正直に解説します。","c":"ホワイトニング"},{"u":"articles/whitening-toothpaste.html","t":"ホワイトニング歯磨き粉ってどこまで白くなるの？論文で","d":"ホワイトニング歯磨き粉は本当に歯を白くするのか。着色（ステイン）にどこまで効くのか、限界はどこかを、現役歯科医師が最新のシステマティックレビューをもとに解説します。","c":"ホワイトニング"},{"u":"articles/wisdom-tooth.html","t":"親知らずって抜いた方がいいの？抜歯の判断を論文で","d":"痛くない親知らずも抜くべき？症状のない埋伏した親知らずを「抜く」か「残す」か、コクランレビューをもとに、判断のポイントと注意点を現役歯科医師がやさしく解説します。","c":"歯内・外科"},{"u":"articles/xylitol.html","t":"キシリトールって本当に虫歯予防になるの？効果を論文で","d":"キシリトールのガムやタブレットは虫歯予防に効くの？コクランレビューをもとに、フッ化物歯磨剤への配合で得られた予防効果と、過度な期待をしないための注意点を現役歯科医師が解説します。","c":"オーラルケア"}];
